import React from 'react';

const Login: React.FC = () => {
  return (
    <div className="flex min-h-screen items-center justify-center bg-slate-900">
      <div className="rounded-lg bg-slate-800 p-8 shadow-xl border border-slate-700">
        <h1 className="text-3xl font-bold text-white mb-4">StreamStack</h1>
        <p className="text-slate-400 mb-6">Welcome back! Please login.</p>
        
        <button className="w-full rounded bg-blue-600 py-2 font-semibold text-white hover:bg-blue-500 transition-colors">
          Sign In
        </button>
      </div>
    </div>
  );
};

export default Login;
